```class Solution {
public:
    int minPartitions(string n) {
        int result = INT_MAX;
        int sum = 0;
        for (int i = n.length() - 1; i >= 0; i--) {
            sum += n[i] - '0';
            result = min(result, sum / 10);
            sum %= 10;
        }
        return result;
    }
};
```

